import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as l,c as e,f as a}from"./app-e7c604ce.js";const s={},t=a('<h3 id="实现一个复杂需求的步骤" tabindex="-1"><a class="header-anchor" href="#实现一个复杂需求的步骤" aria-hidden="true">#</a> 实现一个复杂需求的步骤</h3><ol><li>需求分解：拆分小功能点，如一个协作办公的功能分为：多人文档、表格、ppt、富文本等</li><li>核心功能提取：特别重要如在线多人协助表单重难点：1 多人在线问题，同时操作覆盖问题；2 数据存取问题</li><li>前端技术调研 <ul><li>参考市面类似的项目，如协作办公有钉钉、飞书、云文档、腾讯文档；快速获取信息，如它们使用的插件、前端怎么实现的</li><li>学会有效搜索，百度谷歌掘金npm github等。如协作办公功能搜索多人协作办公、js在线多人协作、前端多人表格等等</li><li>尽量多对比几套方案的优缺点以及匹配度，可以个性化改造达到目的</li></ul></li><li>先验证后使用：做一个最简单的demo来实验 覆盖使用场景</li></ol><h3 id="组件库需求背景" tabindex="-1"><a class="header-anchor" href="#组件库需求背景" aria-hidden="true">#</a> 组件库需求背景？</h3><p>为了提供开发效率，统一ui风格，方便后面的人快速上手，代码维护</p><h3 id="组件库设计" tabindex="-1"><a class="header-anchor" href="#组件库设计" aria-hidden="true">#</a> 组件库设计</h3><ol><li>自动化打包流程，目的是快速被引用，性能兼容设计要求高</li><li>多语言</li><li>按需加载（性能 体积）</li><li>组件文档示例（重要）</li><li>版本修改记录</li><li>自动化创建组件</li><li>单元测试</li></ol><h3 id="组件库与一般项目有什么不同-功能与目录结构" tabindex="-1"><a class="header-anchor" href="#组件库与一般项目有什么不同-功能与目录结构" aria-hidden="true">#</a> 组件库与一般项目有什么不同？--功能与目录结构</h3><ol><li>build文件夹：项目的构建流程相关文件，代码通常是node</li><li>examples文件夹：文档示例，相当于一个小项目</li><li>docs文件夹：项目文档，文件夹下面都是md文件，它有个性化解析规则，里面有：：：demo,里面的的内容会变成element-ui的样式，也就是md文档会转成官网的例子</li><li>packages文件夹：组件的源码，下面有很多小组件推荐去看如何实现的，里面的index.js文件是为了方便按需引入。</li><li>src文件夹：通用的指令，一些公共代码</li><li>types文件夹：ts文件，类型声明组件，支持element-ui可以使用ts文件</li><li>.babelrc：对babel的处理,babel:es5转es6</li><li>.eslintrc: eslin的规范声明</li><li>components.Json：每个组件的映射入口地址 组件名：组件地址</li><li>Makefile：管理命令，命令的集合入口 如make install</li><li>package.Json：项目的灵魂，里面包含项目名字 版本号 依赖 scripts等信息</li></ol>',8),r=[t];function n(o,d){return l(),e("div",null,r)}const _=i(s,[["render",n],["__file","组件库之设计.html.vue"]]);export{_ as default};
